import scala.collection.mutable
import scala.collection.mutable.PriorityQueue

def solve(n: Long, edges: Array[Array[Long]]): Long = {
    // Build adjacency list
    val adj = Array.fill(n.toInt)(mutable.ListBuffer.empty[(Int, Long, Long)])
    for (edge <- edges) {
        val u = edge(0).toInt
        val v = edge(1).toInt
        val start = edge(2)
        val end = edge(3)
        adj(u) += ((v, start, end))
    }

    // Min-heap using PriorityQueue (ordered by time)
    implicit val ord: Ordering[(Long, Int)] = Ordering.by(-_._1)
    val heap = mutable.PriorityQueue.empty[(Long, Int)]
    heap.enqueue((0L, 0))

    // Visited map to track earliest time for each node
    val visited = mutable.Map.empty[Int, Long]
    visited(0) = 0L

    while (heap.nonEmpty) {
        val (currentTime, u) = heap.dequeue()
        if (u == n - 1) {
            return currentTime
        }

        if (currentTime > visited.getOrElse(u, Long.MaxValue)) {
            continue
        }

        // Option 1: Stay at current node (wait 1 time unit)
        val newTime = currentTime + 1
        if (newTime < visited.getOrElse(u, Long.MaxValue)) {
            visited(u) = newTime
            heap.enqueue((newTime, u))
        }

        // Option 2: Try all outgoing edges
        for ((v, start, end) <- adj(u)) {
            val earliestDeparture = math.max(currentTime, start)
            if (earliestDeparture <= end) {
                val arrivalTime = earliestDeparture + 1
                if (arrivalTime < visited.getOrElse(v, Long.MaxValue)) {
                    visited(v) = arrivalTime
                    heap.enqueue((arrivalTime, v))
                }
            }
        }
    }

    -1L
}
